import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const superscriptRole = {
    name: 'superscript',
    alias: ['sup'],
    options: { ...commonRoleOptions('superscript') },
    body: {
        type: 'myst',
        required: true,
    },
    run(data) {
        const node = { type: 'superscript', children: data.body };
        addCommonRoleOptions(data, node);
        return [node];
    },
};
